// Filter leads that have been silent for 48 hours and are Warm or Hot
const now = Date.now();
const fortyEightHours = 48 * 60 * 60 * 1000;
const items = $input.all();

const staleLeads = items.filter(item => {
  const leadStatus = item.json['Lead Status'];
  const lastUpdated = item.json['Last Updated'];
  const phoneNumber = item.json['Phone Number'];
  const leadScore = item.json['Lead Score'];

  if (!lastUpdated || !phoneNumber) return false;
  if (leadStatus === 'Enrolled' || leadStatus === 'Lost') return false;
  if (!['Hot', 'Warm'].includes(leadScore)) return false;

  const lastUpdateTs = new Date(lastUpdated).getTime();
  const ageMs = now - lastUpdateTs;
  return ageMs >= fortyEightHours && ageMs < (fortyEightHours + 3600000);
});

return staleLeads;

